uv run --with requests --with websockets python - <<'PY'
import asyncio, json, base64, re
import requests
import websockets

URL = 'https://stackoverflow.com/questions/11227809/why-is-processing-a-sorted-array-faster-than-processing-an-unsorted-array'

# create a new debuggable tab
resp = requests.get('http://127.0.0.1:9222/json/new?about:blank', timeout=10)
if resp.status_code >= 400:
    # newer chrome sometimes requires PUT
    resp = requests.put('http://127.0.0.1:9222/json/new?about:blank', timeout=10)
resp.raise_for_status()
ws_url = resp.json()['webSocketDebuggerUrl']

events = []

async def main():
    async with websockets.connect(ws_url, max_size=None) as ws:
        msg_id = 0
        pending = {}

        async def send(method, params=None):
            nonlocal msg_id
            msg_id += 1
            payload = {'id': msg_id, 'method': method}
            if params is not None:
                payload['params'] = params
            await ws.send(json.dumps(payload))
            fut = asyncio.get_running_loop().create_future()
            pending[msg_id] = fut
            return await fut

        async def recv_loop():
            while True:
                raw = await ws.recv()
                data = json.loads(raw)
                if 'id' in data and data['id'] in pending:
                    pending.pop(data['id']).set_result(data)
                else:
                    events.append(data)

        recv_task = asyncio.create_task(recv_loop())

        await send('Page.enable')
        await send('Runtime.enable')
        await send('Emulation.setDeviceMetricsOverride', {
            'width': 1400,
            'height': 5000,
            'deviceScaleFactor': 1,
            'mobile': False
        })
        await send('Page.navigate', {'url': URL})

        # wait for load event
        for _ in range(200):
            await asyncio.sleep(0.1)
            if any(e.get('method') == 'Page.loadEventFired' for e in events):
                break
        await asyncio.sleep(1.5)

        js = r"""
(() => {
  const accepted = document.querySelector('.answer.accepted-answer, .answer.js-accepted-answer');
  if (!accepted) return { error: 'accepted-not-found' };

  accepted.scrollIntoView({ block: 'start', behavior: 'instant' });

  const voteText = (accepted.querySelector('.js-vote-count')?.textContent || '').trim();
  const author = (accepted.querySelector('.user-details a')?.textContent || accepted.querySelector('.user-details')?.textContent || '').trim();
  const codeCount = accepted.querySelectorAll('pre, code').length;

  let totalAnswers = null;
  const h2 = document.querySelector('#answers-header h2');
  if (h2) {
    const m = (h2.textContent || '').replace(/,/g, '').match(/(\d+)/);
    if (m) totalAnswers = Number(m[1]);
  }
  if (totalAnswers === null) {
    const byAttr = document.querySelector('[data-answercount]');
    if (byAttr) {
      const v = byAttr.getAttribute('data-answercount');
      if (v && /^\d+$/.test(v)) totalAnswers = Number(v);
    }
  }

  const r = accepted.getBoundingClientRect();
  return {
    voteText,
    author,
    codeCount,
    totalAnswers,
    clip: {
      x: Math.max(0, r.left - 8),
      y: Math.max(0, r.top - 8),
      width: Math.ceil(r.width + 16),
      height: Math.ceil(r.height + 16)
    }
  };
})()
"""

        res = await send('Runtime.evaluate', {'expression': js, 'returnByValue': True})
        out = res.get('result', {}).get('result', {}).get('value', {})
        if out.get('error'):
            raise RuntimeError(out['error'])

        clip = out['clip']
        shot = await send('Page.captureScreenshot', {
            'format': 'png',
            'clip': {
                'x': clip['x'],
                'y': clip['y'],
                'width': max(1, clip['width']),
                'height': max(1, clip['height']),
                'scale': 1
            },
            'captureBeyondViewport': True
        })
        img_b64 = shot.get('result', {}).get('data')
        if not img_b64:
            raise RuntimeError('no screenshot data')
        with open('eval-so-audit.png', 'wb') as f:
            f.write(base64.b64decode(img_b64))

        # close tab
        tid = requests.get('http://127.0.0.1:9222/json', timeout=10).json()
        for t in tid:
            if t.get('webSocketDebuggerUrl') == ws_url:
                requests.get(f"http://127.0.0.1:9222/json/close/{t['id']}", timeout=10)
                break

        recv_task.cancel()
        print(json.dumps({
            'voteText': out.get('voteText', ''),
            'author': out.get('author', ''),
            'codeCount': out.get('codeCount', 0),
            'totalAnswers': out.get('totalAnswers', 0)
        }))

asyncio.run(main())
PY
